from cryptography.fernet import Fernet

# Generate a key for encryption and decryption
# This should be done once and stored securely
key = Fernet.generate_key()

# Store the key in application config
app_config = {
    'encryption_key': key
}

def encrypt_credit_card(credit_card_number):
    fernet = Fernet(app_config['encryption_key'])
    encrypted = fernet.encrypt(credit_card_number.encode())
    return encrypted

def decrypt_credit_card(encrypted_credit_card):
    fernet = Fernet(app_config['encryption_key'])
    decrypted = fernet.decrypt(encrypted_credit_card).decode()
    return decrypted

